function compareArrays(
  a: number[],
  aLength: number,
  b: number[],
  bLength: number,
) {
  const length = Math.min(aLength, bLength);
  for (let i = 0; i < length; i++) {
    const aValue = a[i];
    const bValue = b[i];
    if (aValue !== bValue) {
      return aValue - bValue;
    }
