    Expand<Pick<Type, Extract<keyof Type, K>>>,
    Expand<Pick<Fields, K>>,
    IsOptional
  > {
    const newFields: Record<string, GenericValidator> = {};
    for (const field of fields) {
      newFields[field] = this.fields[field];
    }
