  //  Comparisons  /////////////////////////////////////////////////////////////

  eq<FieldName extends GenericVectorIndexConfig["filterFields"]>(
    fieldName: FieldName,
    value: FieldTypeFromFieldPath<GenericDocument, FieldName>,
  ): FilterExpression<boolean> {
    if (typeof fieldName !== "string") {
